# The regex matches a whole line containing the tab (assuming they are one line)
# E.g. <div class="nav-tab off" onclick="navTap('search')"><svg...></svg><span class="nav-tab-lbl">Search</span></div>
# Let's match `<div class="nav-tab[^>]+onclick="navTap\('([^']+)'\).*?</div>` and replace the svg inside it.

def replace_svg(match):
    full_str = match.group(0)
    tab_name = match.group(3)
    class_str = match.group(1)
    
    is_active = True
    if 'off' in class_str or ('tab-item' in class_str and 'active' not in class_str):
        is_active = False

    new_svg = icons.get(tab_name, {}).get('active' if is_active else 'inactive', '')
    
    # We replace everything from <svg... to </svg> inside full_str with new_svg
    new_str = re.sub(r'<svg.*?</svg>', new_svg, full_str, count=1, flags=re.DOTALL)
    
    # Also if it's inactive, the span text color should match #888
    if not is_active:
        new_str = re.sub(r'(class="(?:nav-tab-lbl|tab-item-lbl)")', r'\1 style="color:#888;"', new_str)
        
    return new_str

pattern = r'<div class="(nav-tab|tab-item)([^"]*)"[^>]*onclick="navTap\(\'([a-z]+)\'\)".*?</div>'
new_html = re.sub(pattern, replace_svg, html, flags=re.DOTALL)

# Let's also fix the opacity of nav-tab.off and tab-item (inactive) to 1 since we are using #888 explicitly.
new_html = new_html.replace('.nav-tab.off{opacity:.42;}', '.nav-tab.off{opacity:1;}')

with open('anda-pay-prototype.html', 'w', encoding='utf-8') as f:
    f.write(new_html)

print("Done")
